source:
* BQ24074 behavioral transient macromodel for ngspice/PSpice-style ABM
* Derived from TI BQ2407x datasheet SLUS810N electrical characteristics and figures.
* Scope: OUT regulation, BAT regulation, charge-current taper, DPPM reduction,
* VIN-DPM input-current foldback, and battery supplement. Default currents are
* set for application-curve style transient testing.
* Not modeled: timers, TS temperature faults, thermal regulation dynamics, startup fault latches.
.SUBCKT BQ24074_TRANS TS BAT N_CE EN2 EN1 N_PGOOD VSS N_CHG OUT ILIM IN TMR ITERM ISET EP
.PARAM VBATREG=4.2 VLOWV=3.0 VOUTREG=4.4 VDPPM=4.3 VINDPM=4.35 ICHG=0.28 ILIMAX=0.9 IOUTMAX=1.3 VINPMIN=3.4 VINOVP=10.5
.FUNC CLAMP(x,lo,hi) { min(max(x,lo),hi) }
R_ISET_BIAS ISET VSS 1MEG
R_ILIM_BIAS ILIM VSS 1MEG
R_TS_LEAK TS VSS 100MEG
R_TMR_LEAK TMR VSS 100MEG
R_ITERM_LEAK ITERM VSS 100MEG
R_EP EP VSS 1M
E_SUPPLY_OK SUPPLY_OK VSS VALUE { CLAMP((V(IN,VSS)-VINPMIN)/0.02,0,1)*CLAMP((V(IN,VSS)-V(BAT,VSS)-0.055)/0.02,0,1) }
E_OVP_OK_CMD OVP_OK_CMD VSS VALUE { CLAMP((VINOVP-V(IN,VSS))/0.02,0,1) }
R_OVP_FILTER OVP_OK_CMD OVP_OK 1K
C_OVP_FILTER OVP_OK VSS 5N
E_VALID VALID VSS VALUE { V(SUPPLY_OK,VSS)*V(OVP_OK,VSS) }
E_VINDPM_FOLD VINDPM_FOLD VSS VALUE { CLAMP((V(IN,VSS)-(VINDPM-0.08))/0.08,0,1) }
E_ILIM_EFF ILIM_EFF VSS VALUE { ILIMAX*V(VINDPM_FOLD,VSS) }
E_OUTDRV OUT_DRV VSS VALUE { VOUTREG*V(VALID,VSS) + CLAMP(V(BAT,VSS)-0.05,0,VBATREG)*(1-V(VALID,VSS)) }
R_OUT_REG OUT_DRV OUT 0.2
C_IN_OUT IN OUT 47N
C_IN_BAT IN BAT 47N
G_BSUP BAT OUT VALUE { CLAMP((VDPPM-V(OUT,VSS))/0.7,0,0.3) }
R_OUT_BLEED OUT VSS 10MEG
G_CHG VSS BAT VALUE { CLAMP(ICHG*V(VALID,VSS)*V(VINDPM_FOLD,VSS)*CLAMP((0.8-V(N_CE,VSS))/0.02,0,1)*CLAMP((VBATREG-V(BAT,VSS))/0.15,0,1)*CLAMP((V(OUT,VSS)-V(BAT,VSS))/(VDPPM-V(BAT,VSS)+0.01),0,1),0,V(ILIM_EFF,VSS)) }
G_IN_LOAD IN VSS VALUE { 0.7*V(VALID,VSS)*CLAMP(V(OUT_DRV,OUT)/0.2,0,min(IOUTMAX,V(ILIM_EFF,VSS)+0.4)) }
G_IN_CHG IN VSS VALUE { V(VALID,VSS)*CLAMP(ICHG*V(VINDPM_FOLD,VSS)*CLAMP((VBATREG-V(BAT,VSS))/0.15,0,1),0,V(ILIM_EFF,VSS)) }
E_PGOOD_CTL PGOOD_CTL VSS VALUE { V(VALID,VSS) }
S_PGOOD N_PGOOD VSS PGOOD_CTL VSS SW_OD_ON_HIGH
E_CHG_CTL CHG_CTL VSS VALUE { CLAMP((0.8-V(N_CE,VSS))/0.02,0,1)*CLAMP((VBATREG-0.01-V(BAT,VSS))/0.02,0,1) }
S_CHG N_CHG VSS CHG_CTL VSS SW_OD_ON_HIGH
.MODEL SW_OD_ON_HIGH SW(Roff=100MEG Ron=20 Vt=0.5 Vh=0.3)
.ENDS BQ24074_TRANS
